import requests
import json
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth
import sys


class RabbitMQManager:
    def __init__(self, host: str = "localhost", port: int = 15672, 
                 username: str = "guest", password: str = "guest"):
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(username, password)
        self.headers = {"Content-Type": "application/json"}
    
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        try:
            if method == "GET":
                response = requests.get(url, auth=self.auth, headers=self.headers)
            elif method == "PUT":
                response = requests.put(url, auth=self.auth, headers=self.headers, 
                                       json=data if data else {})
            elif method == "DELETE":
                response = requests.delete(url, auth=self.auth, headers=self.headers)
            elif method == "POST":
                response = requests.post(url, auth=self.auth, headers=self.headers, json=data)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {e}")
            sys.exit(1)
    
    def create_vhost(self, vhost_name: str) -> bool:
        print(f"Creating virtual host: {vhost_name}")
        response = self._make_request("PUT", f"vhosts/{vhost_name}")
        
        if response.status_code in [201, 204]:
            print(f"✓ Virtual host '{vhost_name}' created successfully")
            return True
        else:
            print(f"✗ Failed to create virtual host '{vhost_name}': {response.status_code} - {response.text}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f"Deleting virtual host: {vhost_name}")
        response = self._make_request("DELETE", f"vhosts/{vhost_name}")
        
        if response.status_code == 204:
            print(f"✓ Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete virtual host '{vhost_name}': {response.status_code}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        response = self._make_request("GET", "vhosts")
        
        if response.status_code == 200:
            vhosts = response.json()
            print(f"\nExisting virtual hosts ({len(vhosts)}):")
            for vhost in vhosts:
                print(f"  - {vhost['name']}")
            return vhosts
        else:
            print(f"✗ Failed to list virtual hosts: {response.status_code}")
            return []
    
    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        print(f"Creating user: {username}")
        data = {
            "password": password,
            "tags": tags
        }
        response = self._make_request("PUT", f"users/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ User '{username}' created successfully")
            return True
        else:
            print(f"✗ Failed to create user '{username}': {response.status_code} - {response.text}")
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f"Deleting user: {username}")
        response = self._make_request("DELETE", f"users/{username}")
        
        if response.status_code == 204:
            print(f"✓ User '{username}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete user '{username}': {response.status_code}")
            return False
    
    def list_users(self) -> List[Dict]:
        response = self._make_request("GET", "users")
        
        if response.status_code == 200:
            users = response.json()
            print(f"\nExisting users ({len(users)}):")
            for user in users:
                print(f"  - {user['name']} (tags: {user.get('tags', 'none')})")
            return users
        else:
            print(f"✗ Failed to list users: {response.status_code}")
            return []
    
    def set_permissions(self, username: str, vhost: str, 
                       configure: str = ".*", write: str = ".*", read: str = ".*") -> bool:
        print(f"Setting permissions for user '{username}' on vhost '{vhost}'")
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        response = self._make_request("PUT", f"permissions/{vhost}/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Permissions set successfully")
            print(f"  Configure: {configure}")
            print(f"  Write: {write}")
            print(f"  Read: {read}")
            return True
        else:
            print(f"✗ Failed to set permissions: {response.status_code} - {response.text}")
            return False
    
    def get_permissions(self, username: str, vhost: str) -> Optional[Dict]:
        response = self._make_request("GET", f"permissions/{vhost}/{username}")
        
        if response.status_code == 200:
            return response.json()
        else:
            return None
    
    def list_permissions(self, vhost: Optional[str] = None) -> List[Dict]:
        if vhost:
            endpoint = f"vhosts/{vhost}/permissions"
        else:
            endpoint = "permissions"
        
        response = self._make_request("GET", endpoint)
        
        if response.status_code == 200:
            permissions = response.json()
            print(f"\nPermissions{' for vhost ' + vhost if vhost else ''} ({len(permissions)}):")
            for perm in permissions:
                print(f"  - User: {perm['user']}, VHost: {perm['vhost']}")
                print(f"    Configure: {perm['configure']}, Write: {perm['write']}, Read: {perm['read']}")
            return permissions
        else:
            print(f"✗ Failed to list permissions: {response.status_code}")
            return []
    
    def delete_permissions(self, username: str, vhost: str) -> bool:
        print(f"Deleting permissions for user '{username}' on vhost '{vhost}'")
        response = self._make_request("DELETE", f"permissions/{vhost}/{username}")
        
        if response.status_code == 204:
            print(f"✓ Permissions deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete permissions: {response.status_code}")
            return False
    
    def set_topic_permissions(self, username: str, vhost: str, exchange: str,
                             write: str = ".*", read: str = ".*") -> bool:
        print(f"Setting topic permissions for user '{username}' on vhost '{vhost}' for exchange '{exchange}'")
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        response = self._make_request("PUT", f"topic-permissions/{vhost}/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Topic permissions set successfully")
            return True
        else:
            print(f"✗ Failed to set topic permissions: {response.status_code} - {response.text}")
            return False
    
    def check_health(self) -> bool:
        response = self._make_request("GET", "overview")
        
        if response.status_code == 200:
            overview = response.json()
            print(f"\n✓ RabbitMQ is healthy")
            print(f"  Version: {overview.get('rabbitmq_version', 'unknown')}")
            print(f"  Cluster name: {overview.get('cluster_name', 'unknown')}")
            return True
        else:
            print(f"✗ RabbitMQ health check failed: {response.status_code}")
            return False


def setup_multi_tenant_environment(manager: RabbitMQManager):
    print("\n" + "="*60)
    print("Setting up Multi-Tenant RabbitMQ Environment")
    print("="*60 + "\n")
    
    # Check RabbitMQ health
    if not manager.check_health():
        print("RabbitMQ is not accessible. Exiting.")
        return
    
    # Define tenant configurations
    tenants = [
        {
            "name": "app1",
            "vhost": "/app1",
            "users": [
                {"username": "app1_producer", "password": "prod_pass123", "tags": ""},
                {"username": "app1_consumer", "password": "cons_pass123", "tags": ""}
            ]
        },
        {
            "name": "app2",
            "vhost": "/app2",
            "users": [
                {"username": "app2_producer", "password": "prod_pass456", "tags": ""},
                {"username": "app2_consumer", "password": "cons_pass456", "tags": ""}
            ]
        },
        {
            "name": "app3",
            "vhost": "/app3",
            "users": [
                {"username": "app3_admin", "password": "admin_pass789", "tags": "administrator"}
            ]
        }
    ]
    
    # Create vhosts and users for each tenant
    for tenant in tenants:
        print(f"\n{'='*60}")
        print(f"Configuring tenant: {tenant['name']}")
        print(f"{'='*60}")
        
        # Create vhost
        manager.create_vhost(tenant["vhost"])
        
        # Create users and set permissions
        for user_config in tenant["users"]:
            username = user_config["username"]
            password = user_config["password"]
            tags = user_config["tags"]
            
            # Create user
            manager.create_user(username, password, tags)
            
            # Set permissions based on user role
            if "producer" in username:
                # Producer: can write to queues/exchanges, read from own queues
                manager.set_permissions(
                    username=username,
                    vhost=tenant["vhost"],
                    configure="^$",  # No configuration rights
                    write=".*",      # Can write to all queues/exchanges
                    read="^$"        # Cannot read (consume)
                )
            elif "consumer" in username:
                # Consumer: can read from queues, no write access
                manager.set_permissions(
                    username=username,
                    vhost=tenant["vhost"],
                    configure="^$",  # No configuration rights
                    write="^$",      # Cannot write
                    read=".*"        # Can read from all queues
                )
            elif "admin" in username:
                # Admin: full access
                manager.set_permissions(
                    username=username,
                    vhost=tenant["vhost"],
                    configure=".*",  # Full configuration rights
                    write=".*",      # Full write access
                    read=".*"        # Full read access
                )
    
    # Create a shared vhost for inter-application communication
    print(f"\n{'='*60}")
    print("Configuring shared vhost for inter-app communication")
    print(f"{'='*60}")
    
    manager.create_vhost("/shared")
    manager.create_user("shared_user", "shared_pass999", "")
    manager.set_permissions(
        username="shared_user",
        vhost="/shared",
        configure=".*",
        write=".*",
        read=".*"
    )
    
    # Summary
    print(f"\n{'='*60}")
    print("Configuration Summary")
    print(f"{'='*60}")
    
    manager.list_vhosts()
    manager.list_users()
    
    print("\n✓ Multi-tenant RabbitMQ environment setup complete!")


def setup_granular_permissions(manager: RabbitMQManager):
    print("\n" + "="*60)
    print("Setting up Granular Permissions Example")
    print("="*60 + "\n")
    
    vhost = "/granular_test"
    manager.create_vhost(vhost)
    
    # User with specific queue access
    manager.create_user("queue_specific_user", "pass123", "")
    manager.set_permissions(
        username="queue_specific_user",
        vhost=vhost,
        configure="^queue_specific_.*",  # Can only configure queues starting with queue_specific_
        write="^queue_specific_.*",      # Can only write to those queues
        read="^queue_specific_.*"        # Can only read from those queues
    )
    
    # User with exchange-specific access
    manager.create_user("exchange_user", "pass456", "")
    manager.set_permissions(
        username="exchange_user",
        vhost=vhost,
        configure="^(amq\\.gen.*|exchange_.*)",  # Can configure exchanges starting with exchange_
        write="^exchange_.*",                     # Can write to those exchanges
        read=".*"                                 # Can read from any queue
    )
    
    manager.list_permissions(vhost)


